function createSyncScriptCode() {
  return new Paragraph({
    spacing: { before: 120, after: 120 },
    children: [new TextRun({ 
      text: `#!/bin/bash

VAULT_PATH="$HOME/Documents/trading-qa"
WORKSPACE_PATH="$HOME/claude-workspace"
DATA_PATH="$WORKSPACE_PATH/data"
LOG_FILE="$VAULT_PATH/.sync/sync.log"

echo "[$(date '+%Y-%m-%d %H:%M:%S')] === Iniciando sincronización ===" >> "$LOG_FILE"

# Crear directorio si no existe
mkdir -p "$DATA_PATH" "$VAULT_PATH/.sync"

# Función: Copiar archivos con log
sync_folder() {
  local src="$1"
  local dest="$2"
  local pattern="$3"

  if [ -d "$src" ]; then
    find "$src" -name "$pattern" -type f | while read file; do
      cp "$file" "$dest/" 2>/dev/null
      echo "  [OK] Copied: $(basename $file)" >> "$LOG_FILE"
    done
  fi
}

# 1. Sincronizar CSVs de backtests
echo "Sincronizando backtests..." >> "$LOG_FILE"
sync_folder "$VAULT_PATH/02-backtests" "$DATA_PATH/backtests" "*.csv"

# 2. Sincronizar Prompt Maestro
echo "Sincronizando prompts..." >> "$LOG_FILE"
[ -f "$VAULT_PATH/01-prompts/prompt-maestro-v2.0.md" ] && \\
  cp "$VAULT_PATH/01-prompts/prompt-maestro-v2.0.md" "$DATA_PATH/" && \\
  echo "  [OK] Prompt Maestro" >> "$LOG_FILE"

# 3. Sincronizar análisis reportes
echo "Sincronizando reportes..." >> "$LOG_FILE"
sync_folder "$VAULT_PATH/06-analysis-reports" "$DATA_PATH/reports" "*.md"

# 4. Actualizar timestamp en INDEX.md
echo "Actualizando INDEX..." >> "$LOG_FILE"
if [ -f "$VAULT_PATH/INDEX.md" ]; then
  sed -i "s/Última actualización:.*/Última actualización: $(date '+%Y-%m-%d %H:%M:%S')/" "$VAULT_PATH/INDEX.md"
fi

# 5. Commit automático en Git (si existe repo)
if [ -d "$VAULT_PATH/.git" ]; then
  cd "$VAULT_PATH"
  git add -A >/dev/null 2>&1
  git commit -m "Auto-sync: $(date '+%Y-%m-%d %H:%M:%S')" >/dev/null 2>&1
  echo "  [OK] Git commit" >> "$LOG_FILE"
fi

echo "[$(date '+%Y-%m-%d %H:%M:%S')] === Sincronización completada ===" >> "$LOG_FILE"
echo "" >> "$LOG_FILE"`,
      font: "Courier New", size: 16 })] 
  });
}

